recomp_func_t recomp_lookup(uint32_t addr) {
    auto it = recomp_func_table.find(addr);
    return (it != recomp_func_table.end()) ? it->second : nullptr;
}

void recomp_dispatch(uint8_t* rdram, recomp_context* ctx, uint32_t addr) {
    // Lazy-init on first call
    if (!recomp_table_ready) recomp_init_dispatch_table();

    // 1. NULL pointer guard
    if (addr == 0) {
        fmt::print(stderr, "[DISPATCH] NULL function pointer! (RA=0x{:08X})\n", ctx->r[31]);
        return;
    }

    // 2. Direct lookup in dispatch table
    recomp_func_t fn = recomp_lookup(addr);
    if (fn) { fn(rdram, ctx); return; }

    // 3. Address normalization (KSEG mirrors) and retry
    uint32_t phys = addr & 0x1FFFFFFFu;
    uint32_t normalized = phys | 0x80000000u;
    if (normalized != addr) {
        fn = recomp_lookup(normalized);
        if (fn) { fn(rdram, ctx); return; }
    }

    // 4. BIOS entry points (A0, B0, C0 — any KSEG mirror)
    if (ctx->bios) {
        if (phys == 0xA0) { ctx->bios->executeA0(); return; }
        if (phys == 0xB0) { ctx->bios->executeB0(); return; }
        if (phys == 0xC0) { ctx->bios->executeC0(); return; }
    }

    // 5. BIOS table sentinel dispatch (B0:xx / C0:xx)
    if (ctx->bios) {
        if (phys >= 0xB000 && phys < 0xB100) {
            ctx->r[9] = phys & 0xFF; // set $t1 = function index
            ctx->bios->executeB0();
            return;
        }
        if (phys >= 0xC000 && phys < 0xC100) {
            ctx->r[9] = phys & 0xFF;
            ctx->bios->executeC0();
            return;
        }
        if (phys >= 0xA000 && phys < 0xA100) {
            ctx->r[9] = phys & 0xFF;
            ctx->bios->executeA0();
            return;
        }
    }

    // 6. JR RA trampoline detection in RAM
    if (phys < 0x200000u) { // Within 2MB main RAM
        uint32_t instr = (uint32_t)rdram[phys] | ((uint32_t)rdram[phys+1] << 8) |
                         ((uint32_t)rdram[phys+2] << 16) | ((uint32_t)rdram[phys+3] << 24);

        // Check GPU device struct BEFORE JR RA trampoline
        {
            uint32_t devStructPtr = (uint32_t)rdram[0x54A64] | ((uint32_t)rdram[0x54A65] << 8) |
                                    ((uint32_t)rdram[0x54A66] << 16) | ((uint32_t)rdram[0x54A67] << 24);
            uint32_t devPhys = devStructPtr & 0x1FFFFFu;
            if (devPhys + 56 <= 0x200000u) {
                auto readPtr = [&](uint32_t off) -> uint32_t {
                    uint32_t a = devPhys + off;
                    return (uint32_t)rdram[a] | ((uint32_t)rdram[a+1] << 8) |
                           ((uint32_t)rdram[a+2] << 16) | ((uint32_t)rdram[a+3] << 24);
                };
                // offset 16 = GPU_cw (writes GP1 command word)
                uint32_t gpu_cw_phys = readPtr(16) & 0x1FFFFFu;
                if (phys == gpu_cw_phys) {
                    if (ctx->mem && ctx->mem->getGPU()) {
                        ctx->mem->getGPU()->writeGP1(ctx->r[4]);
                    }
                    return;
                }
                // offset 4 = GPU_cwc (writes GP0 command word)
                uint32_t gpu_cwc_phys = readPtr(4) & 0x1FFFFFu;
                if (phys == gpu_cwc_phys) {
                    if (ctx->mem && ctx->mem->getGPU()) {
                        ctx->mem->getGPU()->writeGP0(ctx->r[4]);
                    }
                    return;
                }
            }
        }

        if (instr == 0x03E00008u) {
            return; // JR RA trampoline — no-op return
        }
    }

    // 7. Unknown target — rate-limited log (don't crash)
    static std::unordered_map<uint32_t, uint32_t> s_unknownHits;
    auto& hitCount = s_unknownHits[addr];
    if (hitCount < 5) {
        fmt::print(stderr, "[DISPATCH] Unknown target: 0x{:08X} (RA=0x{:08X}, phys=0x{:08X})\n",
                   addr, ctx->r[31], phys);
    } else if (hitCount == 5) {
        fmt::print(stderr, "[DISPATCH] Unknown target: 0x{:08X} — suppressing further logs\n", addr);
    }
    hitCount++;
}
